-- Migration: Create resource_library table, RLS, and seed dataset

CREATE TABLE IF NOT EXISTS resource_library (
  id BIGINT PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY,
  name TEXT NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('Book', 'PDF', 'Video', 'Website')),
  subject TEXT NOT NULL,
  subject_slug TEXT NOT NULL,
  link TEXT NOT NULL,
  rating NUMERIC(3, 1)
);

-- Performance Indexes
CREATE INDEX IF NOT EXISTS idx_resource_library_subject_slug ON resource_library(subject_slug);
CREATE INDEX IF NOT EXISTS idx_resource_library_type ON resource_library(type);

-- Row Level Security (RLS)
ALTER TABLE resource_library ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Allow public select on resource_library" ON resource_library FOR SELECT USING (true);

